INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1e48c2a0-0337-4669-813f-029ab847a013',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Tensor Operations — Broadcasting, Shapes, and GPU Placement$escape$,
  $escape$Keras tensors are thin wrappers over backend tensors (JAX, TensorFlow, or PyTorch), but the Keras ops namespace (`keras.ops`) gives you a unified, backend-agnostic API. Broadcasting follows NumPy rules: a `(3,)` tensor added to a `(4, 3)` tensor expands along axis 0 automatically — no explicit `reshape` needed. Use `keras.ops.expand_dims` when you need explicit control.

Device placement is handled via `keras.distribution` or directly with `keras.ops.device()`. In TF backend, place tensors with `with tf.device('/GPU:0')`. In JAX backend, arrays live on the default device unless you use `jax.device_put`. Keras itself doesn't abstract device context fully — you interact with the backend for fine-grained placement.

For element-wise math, prefer `keras.ops` over raw NumPy: `keras.ops.matmul`, `keras.ops.einsum`, `keras.ops.softmax`. These are differentiable and backend-traced, meaning they work inside `@keras.saving.register_keras_serializable` custom layers without breaking gradient tape or JAX JIT compilation.$escape$,
  $escape$import keras
import numpy as np

# Backend-agnostic tensor ops
x = keras.ops.convert_to_tensor(np.random.rand(4, 3), dtype='float32')
bias = keras.ops.convert_to_tensor(np.array([0.1, 0.2, 0.3]), dtype='float32')

# Broadcasting: (4,3) + (3,) -> (4,3)
out = keras.ops.add(x, bias)

# Einsum for batched dot product
weights = keras.ops.ones((3, 8))
result = keras.ops.einsum('bd,do->bo', out, weights)  # (4, 8)

# Explicit expand_dims for (4,3) -> (4,1,3)
expanded = keras.ops.expand_dims(out, axis=1)
print(expanded.shape)  # (4, 1, 3)$escape$,
