INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '321d1a0f-b987-4167-a8ba-9a849b9d0717',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Training Loop — What Actually Happens Inside model.fit()$escape$,
  $escape$Keras abstracts the training loop behind model.fit(), but understanding what happens under the hood lets you customize and debug effectively. Each training step executes four operations in sequence: a forward pass computes predictions by calling the model on a batch; loss computation invokes your compiled loss function against those predictions and the true labels; backpropagation runs via tf.GradientTape, which recorded all differentiable operations during the forward pass and now computes gradients of the loss w.r.t. every trainable weight; finally, the optimizer step applies those gradients using your chosen algorithm (Adam, SGD, etc.) via optimizer.apply_gradients(). When you override train_step() in a subclassed model, you take direct control of this sequence. This is essential for architectures like GANs where you need separate forward passes and optimizer steps for generator and discriminator. GradientTape context management is the key Keras primitive — everything inside the tape's scope is tracked for differentiation.$escape$,
  $escape$import tensorflow as tf

class CustomModel(tf.keras.Model):
    def train_step(self, data):
        x, y = data

        with tf.GradientTape() as tape:
            y_pred = self(x, training=True)          # forward pass
            loss = self.compiled_loss(y, y_pred)     # loss computation

        gradients = tape.gradient(loss, self.trainable_variables)  # backprop
        self.optimizer.apply_gradients(             # optimizer step
            zip(gradients, self.trainable_variables)
        )
        self.compiled_metrics.update_state(y, y_pred)
        return {m.name: m.result() for m in self.metrics}$escape$,
  $escape$python$escape$,
