INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '026d93e2-5661-4d32-a59f-c87a46a8310f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Optimizers — SGD, Adam, AdamW, and Learning Rate Schedulers That Actually Matter$escape$,
  $escape$Keras ships four optimizers you'll reach for constantly. `SGD` with momentum (`momentum=0.9`, `nesterov=True`) still wins on large-scale vision tasks where generalization beats convergence speed. `Adam` (`learning_rate=1e-3`, `beta_1=0.9`, `beta_2=0.999`) is the default workhorse — adaptive per-parameter rates mean it tolerates poor initialization. `AdamW` adds proper weight decay decoupled from the gradient update, making it the go-to for transformers and fine-tuning; set `weight_decay=0.01` and keep `learning_rate` low (~1e-4). Avoid L2 regularization alongside AdamW — they overlap.

For schedulers, `CosineDecay` smoothly anneals LR to zero, ideal for fixed-epoch runs. Pair it with `CosineDecayRestarts` for cyclical training. `ReduceLROnPlateau` is reactive — cuts LR by `factor=0.5` after `patience=3` stagnant epochs, useful when you don't know your schedule upfront. Compose schedulers into optimizers via `learning_rate=schedule` directly in the constructor — Keras handles the step internally so you never call `.step()` manually.$escape$,
  $escape$import keras

# AdamW + CosineDecay for fine-tuning a transformer
schedule = keras.optimizers.schedules.CosineDecay(
    initial_learning_rate=1e-4,
    decay_steps=10_000,
    alpha=1e-6  # minimum LR floor
)

optimizer = keras.optimizers.AdamW(
    learning_rate=schedule,
    weight_decay=0.01
)

# SGD with Nesterov momentum for vision
sgd = keras.optimizers.SGD(
    learning_rate=0.1,
    momentum=0.9,
    nesterov=True
)

model.compile(optimizer=optimizer, loss="sparse_categorical_crossentropy")$escape$,
  $escape$python$escape$,
