INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e99a35aa-f197-46b4-a007-f242960adac6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Loss Functions — Choosing Right and Writing Custom Ones$escape$,
  $escape$Keras ships with purpose-built losses for every regime. For multi-class classification with integer labels use `SparseCategoricalCrossentropy`; with one-hot vectors use `CategoricalCrossentropy`. For binary outputs, `BinaryCrossentropy`. For regression, `MeanSquaredError` punishes outliers heavily — prefer `Huber` when your targets have noise, since it degrades to MAE beyond a configurable `delta` threshold.

When built-ins don't fit, subclass `keras.losses.Loss`. Override `call(y_true, y_pred)` and return a per-sample tensor — Keras handles reduction internally via the `reduction` argument passed to `__init__`. Avoid Python loops inside `call`; stay in tensor ops so XLA compilation and mixed-precision training remain intact.

Pass `from_logits=True` whenever your final layer has no activation — skipping the sigmoid/softmax in the layer and fusing it into the loss is numerically stabler and avoids the log-of-near-zero trap. This single flag is the most common source of silent accuracy drops in Keras classification pipelines.$escape$,
  $escape$import keras
import tensorflow as tf

class FocalLoss(keras.losses.Loss):
    def __init__(self, gamma=2.0, **kwargs):
        super().__init__(**kwargs)
        self.gamma = gamma

    def call(self, y_true, y_pred):
        bce = keras.losses.binary_crossentropy(
            y_true, y_pred, from_logits=False
        )
        p_t = y_true * y_pred + (1 - y_true) * (1 - y_pred)
        return bce * tf.pow(1.0 - p_t, self.gamma)

model.compile(
    optimizer="adam",
    loss=FocalLoss(gamma=2.0),
)$escape$,
