INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a125ab57-d8ce-4024-95dc-8d6266efc148',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras + XGBoost — Deep Feature Extraction Meets Gradient Boosting$escape$,
  $escape$Pairing a Keras feature extractor with XGBoost frequently outperforms a purely deep classifier on small-to-medium datasets. Use `keras.Model` to expose a penultimate layer's output — a `GlobalAveragePooling2D` or dense embedding — and pass those vectors directly into `xgb.XGBClassifier`.

Key hyperparameters to tune on embedding inputs: `max_depth` (3–6 avoids overfitting on high-dimensional vectors), `learning_rate` (0.01–0.1 paired with sufficient `n_estimators`), and `colsample_bytree` (0.6–0.8 regularizes across 512–1280 embedding dims). Pass an `eval_set` and set `early_stopping_rounds=20` so XGBoost halts before the Keras-derived features overfit.

After fitting, `clf.feature_importances_` returns per-dimension scores across your embedding space. High-importance dims correlate with the semantic concepts the Keras backbone encoded — cross-referencing them with Keras's `GradCAM` or activation maximization reveals exactly what the model keys on. This hybrid pipeline keeps Keras's representation power while gaining XGBoost's interpretability and robustness for the prediction head.$escape$,
  $escape$import numpy as np
import xgboost as xgb
from tensorflow import keras

# Expose penultimate layer from a trained Keras backbone
backbone = keras.applications.MobileNetV2(include_top=False, pooling="avg", weights="imagenet")
feature_extractor = keras.Model(inputs=backbone.input, outputs=backbone.output)

X_train_emb = feature_extractor.predict(X_train_images, batch_size=64)  # (N, 1280)
X_val_emb   = feature_extractor.predict(X_val_images,   batch_size=64)

clf = xgb.XGBClassifier(
    n_estimators=500, max_depth=5,
    learning_rate=0.05, subsample=0.8,
    colsample_bytree=0.7, eval_metric="mlogloss"
)
clf.fit(X_train_emb, y_train,
        eval_set=[(X_val_emb, y_val)],
        early_stopping_rounds=20, verbose=False)

top_dims = np.argsort(clf.feature_importances_)[-10:]  # top 10 embedding dims
print("High-signal Keras embedding dimensions:", top_dims)$escape$,
  $escape$python$escape$,
