INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2da296bc-ba0f-411d-ae6b-2f7b9d1d33d6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras — Functional API, Custom Layers, and Training Loops Demystified$escape$,
  $escape$Keras offers three model-building styles. Sequential is a linear stack — fine for simple pipelines but breaks the moment you need branching or shared layers. The Functional API solves this: you wire `tf.keras.Input` tensors through layers explicitly, enabling multi-input/output models, residual connections, and layer reuse. For anything Sequential can't express, reach for Functional first.

Custom layers go beyond `Lambda` wrappers. Subclass `keras.layers.Layer`, define `build()` to create weight tensors (called once, shape-aware), and `call()` for the forward pass. This keeps weights trackable by `model.trainable_variables`.

Custom training loops replace `model.fit()` with a `tf.GradientTape` block. Inside the tape context, run the forward pass, compute loss, then call `tape.gradient(loss, model.trainable_variables)` and apply updates via your optimizer. This pattern is essential when you need asymmetric gradient flows, multiple losses with different scales, or GAN-style alternating updates that `fit()` cannot express cleanly.$escape$,
  $escape$import keras
import tensorflow as tf

class ScaledDense(keras.layers.Layer):
    def build(self, input_shape):
        self.w = self.add_weight(shape=(input_shape[-1], 64), initializer='glorot_uniform')
        self.scale = self.add_weight(shape=(), initializer='ones')

    def call(self, x):
        return tf.matmul(x, self.w) * self.scale

inputs = keras.Input(shape=(128,))
outputs = ScaledDense()(inputs)
model = keras.Model(inputs, outputs)

optimizer = keras.optimizers.Adam(1e-3)
loss_fn = keras.losses.MeanSquaredError()

for x_batch, y_batch in dataset:
    with tf.GradientTape() as tape:
        preds = model(x_batch, training=True)
        loss = loss_fn(y_batch, preds)
    grads = tape.gradient(loss, model.trainable_variables)
    optimizer.apply_gradients(zip(grads, model.trainable_variables))$escape$,
  $escape$python$escape$,
