INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd173e86-8021-4b8b-a544-2bfa813211f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Keras Production Readiness — Exporting, ONNX Conversion, and Serving$escape$,
  $escape$Keras 3's multi-backend design changes how you think about production export. The canonical path is `model.export('saved_model_dir', format='tf_saved_model')` for TensorFlow Serving, but if you're targeting ONNX for cross-runtime portability, use `tf2onnx` after SavedModel export: `python -m tf2onnx.convert --saved-model saved_model_dir --output model.onnx --opset 17`. For JAX or PyTorch backends, `keras.export.ExportArchive` gives you a backend-agnostic serving artifact. Critical gotcha: dynamic shapes. Always trace with representative input signatures — `model.export(..., input_signature=[tf.TensorSpec([None, 224, 224, 3])])` — or ONNX inference will break on batch size mismatches. For high-throughput serving, prefer TensorFlow Serving's gRPC endpoint over REST; it handles batching natively with `--enable_batching`. Validate your ONNX graph with `onnxruntime.InferenceSession` locally before deploying. Use `ort_session.get_inputs()` to confirm input names match what your serving layer sends — mismatched names are the silent killer in ONNX pipelines.$escape$,
  $escape$import tensorflow as tf
import tf2onnx
import onnxruntime as ort

# Export Keras model to SavedModel
model.export('saved_model_dir', format='tf_saved_model')

# Convert to ONNX with explicit input signature
spec = (tf.TensorSpec([None, 224, 224, 3], tf.float32, name='input'),)
tf2onnx.convert.from_keras(model, input_signature=spec, output_path='model.onnx', opset=17)

# Validate locally before deploying
session = ort.InferenceSession('model.onnx', providers=['CPUExecutionProvider'])
print([inp.name for inp in session.get_inputs()])$escape$,
  $escape$python$escape$,
